import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

import java.io.FileWriter;
import java.io.IOException;

public class XSSFixedCode {

    public static void main(String[] args) {
        Encoder encoder = ESAPI.encoder();

        String userInput = "<script>alert('XSS Vulnerability')</script>";

        String encodedUserInput = encoder.encodeForHTML(userInput);

        String outputHtml = "<html><body><h1>Welcome, " + encodedUserInput + "</h1></body></html>";

        try {
            FileWriter fileWriter = new FileWriter("output.html");
            fileWriter.write(outputHtml);
            fileWriter.close();

            System.out.println("Output HTML file generated successfully!");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

